__EXPECTUNUSEDCATEGORY__
{{Cmbox
| type = move
| image = [[File:Redirect arrow.svg|52px|link=|alt=|class=skin-invert]]
| text = 
'''This category is located at <span id="softredirect">[[:{{#ifeq:{{NAMESPACE:{{{1}}} }}|Category||Category:}}{{trim|{{{1}}}}}]]</span>.'''
<div style="margin-left:1.6em;">[[File:Symbol information vote.svg|16px|link=|alt=]] '''Note:''' This category should be empty.</div>
{{#if:{{{2|}}}|<hr />The following [[Wikipedia:Categorizing redirects|categories]] are used to track and monitor this redirect:
{{{2}}}
<hr />
}}
See the [[Template:Category redirect#Instructions|instructions]] for more information.
{{#if:{{yesno|1={{{keep|}}}}}{{{2|}}}|<!-- Hide the note if we have |keep=yes OR we have a redirect category -->|<small class="sysop-show">'''Administrators''': If this category name is unlikely to be entered on new pages, and all [[Special:WhatLinksHere/{{FULLPAGENAME}}|incoming links]] have been cleaned up, [{{fullurl:{{FULLPAGENAME}}|wpReason={{urlencode:[[WP:CSD#G6|G6]]: This category is located at [[{{#ifeq:{{NAMESPACE:{{{1}}} }}|Category||Category:}}{{{1}}}]]. }}}}&action=delete click here to delete].</small><!-- Close #if:keep -->}}
<!-- Close cmbox -->}}{{category other 
|<!-- 
Reporting if the first parameter is not a valid category name: 
-->{{#ifexist:{{#ifeq:{{NAMESPACE:{{{1}}} }}|Category||Category:}}{{{1}}}
  | 
  | [[Category:Wikipedia category-redirect box parameter needs fixing|∃{{PAGENAME}}]]
  }}<!-- 
Reporting circular redirects (of length 1): 
-->{{#ifeq:{{PAGENAME:{{{1}}}}}|{{PAGENAME}}|[[Category:Wikipedia category-redirect box parameter needs fixing|∞{{PAGENAME}}]]}}
| <div style="margin-left:8em;">This template should only be used on category pages.</div>
}}{{category handler
 |all = {{#ifexpr:{{PAGESINCATEGORY:{{PAGENAME}}|R}}
 |[[Category:Wikipedia non-empty soft redirected categories]]
}}<includeonly>{{Category other|[[Category:Wikipedia soft redirected categories]]|{{Incorrect namespace|category}}}}</includeonly>
|nocat={{{nocat|{{#ifeq:{{FULLPAGENAME}}|MediaWiki:Category-move-redirect-override|true}}}}}
}}<noinclude>
{{Documentation}}
<!-- Add categories to the /doc subpage and interwikis to Wikidata, not here! -->
</noinclude>

